"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[10421],{99475(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>f,frontMatter:()=>s,metadata:()=>i,toc:()=>d});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 19 Employee Benefits/effect-of-a-potential-discount-on-pl-9b3e1ffb3c","title":"Effect of a Potential Discount on Plan Classification (IAS 19)","description":"June 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 19 Employee Benefits/Effect of a Potential Discount on Plan Classification (IAS 19).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 19 Employee Benefits","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-19-employee-benefits-1c4dcadd93/effect-of-a-potential-discount-on-pl-9b3e1ffb3c","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-19-employee-benefits-1c4dcadd93/effect-of-a-potential-discount-on-pl-9b3e1ffb3c","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"effect-of-a-potential-discount-on-pl-9b3e1ffb3c","title":"Effect of a Potential Discount on Plan Classification (IAS 19)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-19-employee-benefits-1c4dcadd93/effect-of-a-potential-discount-on-pl-9b3e1ffb3c","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Attributing Benefit to Periods of Service (IAS 19)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-19-employee-benefits-1c4dcadd93/attributing-benefit-to-periods-of-se-45abc7c877"},"next":{"title":"Costs Necessary to Sell Inventories (IAS 2)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-2-inventories-36d7ac0301/costs-necessary-to-sell-inventories--eca7a0ffcf"}}');var a=n(74848),o=n(28453);let s={id:"effect-of-a-potential-discount-on-pl-9b3e1ffb3c",title:"Effect of a Potential Discount on Plan Classification (IAS 19)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-19-employee-benefits-1c4dcadd93/effect-of-a-potential-discount-on-pl-9b3e1ffb3c",sidebar_position:2},r="Effect of a Potential Discount on Plan Classification (IAS 19)",l={},d=[];function c(e){let t={h1:"h1",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"effect-of-a-potential-discount-on-plan-classification-ias-19",children:"Effect of a Potential Discount on Plan Classification (IAS 19)"})}),"\n",(0,a.jsx)(t.p,{children:"June 2019"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about the classification of a post-employment benefit plan applying IAS 19. In the fact pattern described in the request, an entity sponsors a post- employment benefit plan that is administered by a third party. The relevant terms and conditions of the plan are as follows:"}),"\n",(0,a.jsx)(t.p,{children:"a. the entity has an obligation to pay fixed annual contributions to the plan. The entity has determined that it will have no legal or constructive obligation to pay further contributions if the plan does not hold sufficient assets to pay all employee benefits relating to employee service in the current and prior periods.\nb. the entity is entitled to a potential discount on its annual contributions. The discount arises if the ratio of plan assets to plan liabilities exceeds a set level. Thus, any discount might be affected by actuarial assumptions and the return on\nplan assets."}),"\n",(0,a.jsx)(t.p,{children:"The request asked whether, applying IAS 19, the existence of a right to a potential discount would result in a defined benefit plan classification."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 8 of IAS 19 defines defined contribution plans as \u2018post-employment benefit plans under which an entity pays fixed contributions into a separate entity (a fund) and will have no legal or constructive obligation to pay further contributions if the fund does not hold sufficient assets to pay all employee benefits relating to employee service in the current and prior periods\u2019. Defined benefit plans are \u2018post-employment benefit plans other than defined contribution plans\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Paragraphs 27\u201330 of IAS 19 specify requirements relating to the classification of post-employment benefit plans as either defined contribution plans or defined benefit plans."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 27 states that \u2018[p]ost-employment benefit plans are classified as either defined contribution or defined benefit plans, depending on the economic substance of the plan as derived from its principal terms and conditions\u2019. The Committee therefore noted the importance of assessing all relevant terms and conditions of a post-employment benefit plan, as well as any informal practices that might give rise to a constructive obligation, in\nclassifying the plan. That assessment would identify whether:"}),"\n",(0,a.jsx)(t.p,{children:"a. the entity\u2019s legal or constructive obligation towards employees is limited to the amount that it agrees to contribute to the fund (a defined contribution plan as described in paragraph 28); or\nb. the entity has an obligation to provide the agreed benefits to current and former employees (a defined benefit plan as described in paragraph 30)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee noted that, in the fact pattern described in the request, assessing the relevant terms and conditions of the plan would include, for example, assessing (a) the manner and frequency in which annual contributions and any potential discount (including the target ratio) are determined; and (b) whether the manner and frequency of determining the contributions and any discount transfers actuarial risk and investment risk (as described in IAS 19) to the entity."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, to meet the definition of a defined contribution plan, an entity must (a) have an obligation towards employees to pay fixed contributions into a fund; and (b) not be obliged to pay further contributions if the fund does not hold sufficient assets to pay all employee benefits relating to employee service in the current or prior periods. For example, there should be no possibility that future contributions could be set to cover shortfalls in funding employee benefits relating to employee service in the current and prior periods."}),"\n",(0,a.jsx)(t.p,{children:"The Committee also observed that paragraphs 28 and 30 of IAS 19 specify that, under defined contribution plans, actuarial risk and investment risk fall in substance on the employee whereas, under defined benefit plans, those risks fall in substance on the entity. Paragraphs 28 and 30 describe (a) actuarial risk as the risk that benefits will cost the entity more than expected or will be less than expected for the employee; and (b) investment risk as the risk that assets invested will be insufficient to meet expected benefits. Paragraph BC29 of IAS 19 explains that the definition of defined contribution\nplans does not exclude the upside potential that the cost to the entity may be less than expected."}),"\n",(0,a.jsx)(t.p,{children:"Consequently, the Committee concluded that, applying IAS 19, the existence of a right to a potential discount would not in itself result in classifying a post-employment benefit plan as a defined benefit plan. Nonetheless, the Committee reiterated the importance of assessing all relevant terms and conditions of a plan, as well as any informal practices that might give rise to a constructive obligation, in classifying the plan."}),"\n",(0,a.jsx)(t.p,{children:"The Committee noted that, applying paragraph 122 of IAS 1 Presentation of Financial Statements, an entity would disclose the judgements that its management has made regarding the classification of post-employment benefit plans, if those are part of the judgements that had the most significant effect on the amounts recognised in the financial statements."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the requirements in IAS 19 provide an adequate basis for an entity to determine the classification of a post-employment benefit plan as a defined contribution plan or a defined benefit plan. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function f(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},28453(e,t,n){n.d(t,{R:()=>s,x:()=>r});var i=n(96540);let a={},o=i.createContext(a);function s(e){let t=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:t},e.children)}}}]);